<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Personal Expense Tracker</title>
  <style>
    * { box-sizing: border-box; }
    body {
      font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
      max-width: 720px;
      margin: 0 auto;
      padding: 1rem 1.25rem 2rem;
      color: #1a1a1a;
      line-height: 1.4;
    }
    h1 { font-size: 1.5rem; margin: 0 0 1rem; }
    h2 { font-size: 1.1rem; margin: 1.5rem 0 0.5rem; }
    label { display: block; font-size: 0.85rem; margin-bottom: 0.2rem; font-weight: 600; }
    input, select, button {
      font: inherit;
      padding: 0.4rem 0.5rem;
      margin-bottom: 0.6rem;
    }
    input[type="number"], input[type="date"], input[type="text"], select {
      width: 100%;
      border: 1px solid #ccc;
      border-radius: 4px;
    }
    .row { display: flex; gap: 0.75rem; flex-wrap: wrap; }
    .row > * { flex: 1; min-width: 120px; }
    #add-expense {
      background: #2563eb;
      color: #fff;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      padding: 0.5rem 1rem;
      width: 100%;
    }
    #add-expense:hover { background: #1d4ed8; }
    #form-error {
      color: #b91c1c;
      min-height: 1.25rem;
      font-size: 0.9rem;
      margin: 0 0 0.5rem;
    }
    .filters {
      background: #f5f5f5;
      padding: 0.75rem;
      border-radius: 6px;
      margin-bottom: 1rem;
    }
    .summary {
      display: flex;
      flex-wrap: wrap;
      gap: 0.5rem 1rem;
      align-items: baseline;
      margin-bottom: 0.75rem;
    }
    #total {
      font-size: 1.25rem;
      font-weight: 700;
    }
    .cat-total {
      font-size: 0.9rem;
      background: #eef2ff;
      padding: 0.2rem 0.5rem;
      border-radius: 4px;
    }
    #expense-list { list-style: none; padding: 0; margin: 0; }
    .expense {
      display: flex;
      align-items: center;
      gap: 0.75rem;
      padding: 0.6rem 0.4rem;
      border-bottom: 1px solid #e5e5e5;
    }
    .expense.hidden { display: none; }
    .expense .amt { font-weight: 700; min-width: 4.5rem; }
    .expense .meta { flex: 1; font-size: 0.9rem; }
    .expense .note { color: #555; font-size: 0.85rem; }
    .exp-del {
      background: #fee2e2;
      color: #991b1b;
      border: 1px solid #fecaca;
      border-radius: 4px;
      cursor: pointer;
      padding: 0.25rem 0.5rem;
      margin: 0;
    }
    .exp-del:hover { background: #fecaca; }
    .empty { color: #666; font-size: 0.9rem; padding: 0.5rem 0; }
  </style>
</head>
<body>
  <h1>Expense Tracker</h1>

  <form id="expense-form" novalidate>
    <div class="row">
      <div>
        <label for="amount">Amount</label>
        <input type="number" id="amount" step="0.01" min="0" placeholder="0.00" />
      </div>
      <div>
        <label for="category">Category</label>
        <select id="category">
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div>
        <label for="date">Date</label>
        <input type="date" id="date" />
      </div>
    </div>
    <div>
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="Optional note" />
    </div>
    <p id="form-error"></p>
    <button type="submit" id="add-expense">Add expense</button>
  </form>

  <h2>Filters</h2>
  <div class="filters">
    <div class="row">
      <div>
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div>
        <label for="filter-from">From</label>
        <input type="date" id="filter-from" />
      </div>
      <div>
        <label for="filter-to">To</label>
        <input type="date" id="filter-to" />
      </div>
    </div>
  </div>

  <h2>Summary</h2>
  <div class="summary">
    <div>Total: <span id="total">0.00</span></div>
    <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
    <span class="cat-total" data-cat="transport">transport: 0.00</span>
    <span class="cat-total" data-cat="bills">bills: 0.00</span>
    <span class="cat-total" data-cat="fun">fun: 0.00</span>
  </div>

  <h2>Expenses</h2>
  <ul id="expense-list"></ul>
  <p id="empty-msg" class="empty" hidden>No expenses yet.</p>

  <script>
    const STORAGE_KEY = 'expense-tracker-items';
    const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

    /** @type {{id:string, amount:number, category:string, date:string, note:string}[]} */
    let expenses = [];

    const form = document.getElementById('expense-form');
    const amountEl = document.getElementById('amount');
    const categoryEl = document.getElementById('category');
    const dateEl = document.getElementById('date');
    const noteEl = document.getElementById('note');
    const formError = document.getElementById('form-error');
    const listEl = document.getElementById('expense-list');
    const totalEl = document.getElementById('total');
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');
    const emptyMsg = document.getElementById('empty-msg');

    function load() {
      try {
        const raw = localStorage.getItem(STORAGE_KEY);
        expenses = raw ? JSON.parse(raw) : [];
        if (!Array.isArray(expenses)) expenses = [];
      } catch {
        expenses = [];
      }
    }

    function save() {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    }

    function uid() {
      return Date.now().toString(36) + Math.random().toString(36).slice(2, 9);
    }

    function formatMoney(n) {
      return n.toFixed(2);
    }

    function isVisible(exp) {
      const cat = filterCategory.value;
      if (cat !== 'all' && exp.category !== cat) return false;
      const from = filterFrom.value;
      const to = filterTo.value;
      if (from && exp.date < from) return false;
      if (to && exp.date > to) return false;
      return true;
    }

    function render() {
      listEl.innerHTML = '';
      const sorted = expenses.slice().sort((a, b) => {
        if (a.date !== b.date) return b.date.localeCompare(a.date);
        return b.id.localeCompare(a.id);
      });

      let visibleTotal = 0;
      const catTotals = Object.fromEntries(CATEGORIES.map(c => [c, 0]));
      let any = false;

      for (const exp of sorted) {
        any = true;
        const visible = isVisible(exp);
        const li = document.createElement('li');
        li.className = 'expense' + (visible ? '' : ' hidden');
        li.dataset.id = exp.id;

        const amt = document.createElement('span');
        amt.className = 'amt';
        amt.textContent = formatMoney(exp.amount);

        const meta = document.createElement('div');
        meta.className = 'meta';
        meta.innerHTML =
          '<div><strong>' + escapeHtml(exp.category) + '</strong> · ' +
          escapeHtml(exp.date) + '</div>' +
          (exp.note ? '<div class="note">' + escapeHtml(exp.note) + '</div>' : '');

        const del = document.createElement('button');
        del.type = 'button';
        del.className = 'exp-del';
        del.textContent = 'Delete';
        del.addEventListener('click', () => {
          expenses = expenses.filter(e => e.id !== exp.id);
          save();
          render();
        });

        li.appendChild(amt);
        li.appendChild(meta);
        li.appendChild(del);
        listEl.appendChild(li);

        if (visible) {
          visibleTotal += exp.amount;
          if (catTotals[exp.category] !== undefined) {
            catTotals[exp.category] += exp.amount;
          }
        }
      }

      totalEl.textContent = formatMoney(visibleTotal);
      document.querySelectorAll('.cat-total').forEach(el => {
        const c = el.getAttribute('data-cat');
        el.textContent = c + ': ' + formatMoney(catTotals[c] || 0);
      });

      emptyMsg.hidden = any;
    }

    function escapeHtml(s) {
      return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
    }

    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const rawAmount = amountEl.value.trim();
      const amount = Number(rawAmount);
      const date = dateEl.value;
      const category = categoryEl.value;
      const note = noteEl.value.trim();

      if (
        rawAmount === '' ||
        !Number.isFinite(amount) ||
        amount <= 0 ||
        !date
      ) {
        formError.textContent =
          'Please enter a positive amount and a date.';
        return;
      }

      formError.textContent = '';
      expenses.push({
        id: uid(),
        amount: Math.round(amount * 100) / 100,
        category,
        date,
        note
      });
      save();
      amountEl.value = '';
      noteEl.value = '';
      render();
    });

    filterCategory.addEventListener('change', render);
    filterFrom.addEventListener('change', render);
    filterTo.addEventListener('change', render);

    // Default date to today for convenience
    if (!dateEl.value) {
      const t = new Date();
      const yyyy = t.getFullYear();
      const mm = String(t.getMonth() + 1).padStart(2, '0');
      const dd = String(t.getDate()).padStart(2, '0');
      dateEl.value = yyyy + '-' + mm + '-' + dd;
    }

    load();
    render();
  </script>
</body>
</html>
